import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void testValueTrue() throws IOException {
    jsonWriter.value(true);
    assertEquals("true", stringWriter.toString());
  }

  @Test
  public void testValueFalse() throws IOException {
    jsonWriter.value(false);
    assertEquals("false", stringWriter.toString());
  }

  @Test
  public void testValueCallsWriteDeferredNameAndBeforeValue() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    // Spy on JsonWriter to verify private method calls
    JsonWriter spyWriter = spy(new JsonWriter(stringWriter));

    // Use reflection to access private methods
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);

    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);

    // Call value(boolean) on spy
    spyWriter.value(true);

    // Verify that private methods were called once each
    verify(spyWriter, times(1)).value(true);
    // Because these are private and not mocked, verify private calls via reflection invocation count is not possible directly.
    // Instead, we invoke private methods separately to ensure they don't throw exceptions.
    writeDeferredNameMethod.invoke(spyWriter);
    beforeValueMethod.invoke(spyWriter);

    // Verify output
    assertEquals("truetrue", stringWriter.toString()); // Because we invoked writeDeferredName and beforeValue again which do not write directly, only value writes "true"
  }

  @Test
  public void testValueWithDeferredNameWritesNameBeforeValue() throws IOException, NoSuchFieldException, IllegalAccessException {
    // Set deferredName to a non-null value to test that writeDeferredName writes the name first
    java.lang.reflect.Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(jsonWriter, "myName");

    // Also push EMPTY_OBJECT on stack to allow name writing
    java.lang.reflect.Field stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    int[] stack = (int[]) stackField.get(jsonWriter);
    stack[0] = 1; // NONEMPTY_OBJECT
    java.lang.reflect.Field stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.set(jsonWriter, 1);

    jsonWriter.value(true);
    String output = stringWriter.toString();

    // It should write the name and then the value true
    assertTrue(output.contains("myName"));
    assertTrue(output.contains("true"));
  }

  @Test
  public void testValueReturnsThis() throws IOException {
    JsonWriter result = jsonWriter.value(true);
    assertSame(jsonWriter, result);
  }
}
